        if (node.left != null) {
            inorderTraversal(node.left);
        }
        if (prev != null) {
            result = Math.min(result, node.val - prev.val);
        }
        prev = node;
        if (node.right != null) {
            inorderTraversal(node.right);
        }
    }
}

