import java.util.*;

public class Solution {
    public String splitLoopedString(String[] strs) {
        String ans = "", cur = "";
        for (String s : strs) {
            String rev = new StringBuilder(s).reverse().toString();
            cur += (s.compareTo(rev) > 0) ? s : rev;
        }

        int k = 0;
        for (int i = 0; i < strs.length; i++) {
            processLoop(strs, ans, cur, k);
            k += strs[i].length();
        }
        return ans;
    }

    private void processLoop(String[] strs, String ans, String cur, int k) {
        String rev = new StringBuilder(strs[k]).reverse().toString();
        for (String xstr : Arrays.asList(strs[k], rev)) {
            handleSubstring(xstr, ans, cur, k);
        }
    }

    private void handleSubstring(String xstr, String ans, String cur, int k) {
        for (int j = 0; j < xstr.length(); j++) {
            String t = xstr.substring(j) + cur.substring(k + xstr.length()) + cur.substring(0, k) + xstr.substring(0, j);
            if (ans.compareTo(t) > 0) {
                ans = t;
            }
        }
    }
}

