public class Solution {
    public int triangleNumber(int[] nums) {
        Arrays.sort(nums);
        int count = 0;
        for (int i = 0; i < nums.length - 2; ++i) {
            for (int j = i + 1, k = j + 1; j < nums.length - 1 && nums[i] != 0; ++j) {
                while (k < nums.length && nums[i] + nums[j] > nums[k]) {
                    ++k;
                }
                count += k - j - 1;
            }
        }
        return count;
    }
}

