public class Solution {
    public int maxDistToClosest(int[] seats) {
        int n = seats.length;
        if (n == 0) return -1; // Handle edge case

        int maxDist = 0, lastPerson = -1;

        for (int i = 0; i < n; ++i) {
            if (seats[i] == 1) {
                if (lastPerson == -1)
                    return Math.max(maxDist, i);

                maxDist = Math.max(maxDist, (i - lastPerson) / 2);
                lastPerson = i;
            }
        }

        return Math.max(maxDist, n - 1 - lastPerson);
    }
}

