public class Solution {
    public String lexSmallestEquivalent(String s1, String s2, String baseStr) {
        Map<Character, Character> parent = new HashMap<>();
        for (char ch = 'a'; ch <= 'z'; ch++) {
            parent.put(ch, ch);
        }

        // Union-Find to find the smallest equivalent character
        for (int i = 0; i < s1.length(); i++) {
            char root1 = s1.charAt(i), root2 = s2.charAt(i);
            while (parent.get(root1) != root1) root1 = parent.get(root1);
            while (parent.get(root2) != root2) root2 = parent.get(root2);
            if (root1 != root2) {
                char minRoot = (char) Math.min(root1, root2);
                parent.put(root1, minRoot);
                parent.put(root2, minRoot);
            }
        }

        // Build the result string using the smallest equivalent characters
        StringBuilder sb = new StringBuilder();
        for (char ch : baseStr.toCharArray()) {
            while (parent.get(ch) != ch) ch = parent.get(ch);
            sb.append(ch);
        }

        return sb.toString();
    }
}

